// Define the target app URL to monitor
return [{
  json: {
    targetUrl: 'https://demo.realworld.io',
    checkTime: new Date().toISOString()
  }
}];

// Capture response time and status code
const startTime = new Date($('Set Target URL').first().json.checkTime).getTime();
const endTime = Date.now();
const responseTimeMs = endTime - startTime;

const response = $input.first().json;
const statusCode = response.statusCode || response.status || 200;

return [{
  json: {
    url: $('Set Target URL').first().json.targetUrl,
    statusCode,
    responseTimeMs,
    checkTime: $('Set Target URL').first().json.checkTime,
    isHealthy: statusCode === 200 && responseTimeMs < 5000
  }
}];

// App is UP — log silently, no Discord noise
console.log('Uptime OK:', JSON.stringify($input.first().json));
return [];

// Build alert payload for DOWN / slow / non-200
const d = $input.first().json;
const isTimeout = !d.statusCode;
const statusLabel = isTimeout ? 'TIMEOUT / UNREACHABLE' : `HTTP ${d.statusCode}`;
const slowWarning = d.responseTimeMs > 5000 ? ' ⚠️ Slow response detected.' : '';

return [{
  json: {
    username: 'Uptime Monitor',
    avatar_url: 'https://cdn-icons-png.flaticon.com/512/1010/1010888.png',
    embeds: [{
      title: '🚨 App Down / Degraded',
      description: [
        `**URL:** ${d.url}`,
        `**Status:** ${statusLabel}${slowWarning}`,
        `**Response Time:** ${d.responseTimeMs ?? 'N/A'} ms`,
        `**Detected at:** ${d.checkTime}`
      ].join('\n'),
      color: 15158332
    }]
  }
}];

// Handle connection error (app completely unreachable)
const err = $input.first().json;
return [{
  json: {
    url: $('Set Target URL').first().json.targetUrl,
    statusCode: null,
    responseTimeMs: null,
    checkTime: $('Set Target URL').first().json.checkTime,
    isHealthy: false,
    error: err.message || JSON.stringify(err)
  }
}];

// Daily summary — in production this would aggregate logs from a DB or n8n static data
// For demo purposes we send a summary template
const now = new Date();
return [{
  json: {
    username: 'Uptime Monitor',
    embeds: [{
      title: '📊 Daily Uptime Summary',
      description: [
        `**Date:** ${now.toDateString()}`,
        `**Monitored App:** https://demo.realworld.io`,
        `**Check Frequency:** Every 5 minutes`,
        `**Total Checks:** ~288`,
        '**Incidents logged:** See n8n execution history',
        '',
        '_To aggregate real stats, connect this workflow to a database or n8n static data store._'
      ].join('\n'),
      color: 3447003,
      footer: { text: 'Uptime Monitor — Automation & QA Assessment' }
    }]
  }
}];
